import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';

function App() {
  return (
    <Router>
      <div className="container mt-5">
        <h1 className="text-primary text-center">Trouve ton artisan</h1>
        <p className="text-center">Si ce message s'affiche, le problème est résolu !</p>
      </div>
    </Router>
  );
}

export default App;
